use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF file
sub extract_text {
    my ($filename) = @_;
    my $pdf = PDF::API2->open($filename);
    my $pages = $pdf->pages;

    my $text = '';
    for my $page (1 .. $pages) {
        $text .= $pdf->page($page)->text;
    }

    return $text;
}

