    }
    if ($text =~ /Author:\s*(\w+)/) {
        $info->{author} = $1;
    }
    if ($text =~ /Table:\s*(.*?)\s*(?=Date|\Author)/s) {
        $info->{table} = $1;
    }

    return $info;
}

